import{_ as o,o as i,c as t,a2 as a}from"./chunks/framework.BWuWLRhz.js";const m=JSON.parse('{"title":"Epic: Accessibility","description":"","frontmatter":{},"headers":[],"relativePath":"epics/accessibility.md","filePath":"epics/accessibility.md"}'),c={name:"epics/accessibility.md"};function s(n,e,l,r,d,p){return i(),t("div",null,[...e[0]||(e[0]=[a('<h1 id="epic-accessibility" tabindex="-1">Epic: Accessibility <a class="header-anchor" href="#epic-accessibility" aria-label="Permalink to &quot;Epic: Accessibility&quot;">​</a></h1><blockquote><p>WCAG 2.1 AA compliance for all platform-owned UI, automated a11y linting baked into CI, and a clear plugin developer accessibility contract.</p></blockquote><h2 id="status" tabindex="-1">Status <a class="header-anchor" href="#status" aria-label="Permalink to &quot;Status&quot;">​</a></h2><p>✅ Complete</p><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>Task 0.5.29 established the full a11y baseline: <code>eslint-plugin-jsx-a11y</code> (recommended) runs in CI on all packages; every semantic color pair in the design system meets 4.5:1 text contrast and 3:1 UI-component contrast; <code>prefers-reduced-motion</code> is applied to animated components; focus-visible ring tokens are codified. The audit covered the runtime shell chrome, auth login/registration, Console, Launcher, and Account. Plugin developers get a dedicated &quot;Accessibility&quot; section in <code>docs/plugin-development.md</code>.</p><h2 id="related-rfcs" tabindex="-1">Related RFCs <a class="header-anchor" href="#related-rfcs" aria-label="Permalink to &quot;Related RFCs&quot;">​</a></h2><ul><li><a href="./../rfcs/0025-accessibility.html">RFC 0025 — Accessibility</a></li></ul><h2 id="related-docs" tabindex="-1">Related Docs <a class="header-anchor" href="#related-docs" aria-label="Permalink to &quot;Related Docs&quot;">​</a></h2><ul><li><a href="./../design-system.html">design-system.md — Contrast commitment, focus-visible</a></li><li><a href="./../plugin-development.html">plugin-development.md — Accessibility section</a></li></ul><h2 id="tasks" tabindex="-1">Tasks <a class="header-anchor" href="#tasks" aria-label="Permalink to &quot;Tasks&quot;">​</a></h2><h4 id="✅-10-1-—-accessibility-audit-a11y-contract-rfc-0025" tabindex="-1">✅ 10.1 — Accessibility audit &amp; a11y contract (RFC 0025) <a class="header-anchor" href="#✅-10-1-—-accessibility-audit-a11y-contract-rfc-0025" aria-label="Permalink to &quot;✅ 10.1 — Accessibility audit &amp; a11y contract (RFC 0025)&quot;">​</a></h4><p><strong>Goal:</strong> Reach WCAG 2.1 AA on all platform-owned UI, add automated a11y linting, and deliver the plugin developer a11y contract per RFC 0025.</p><p><strong>Deliverables:</strong></p><ul><li><code>eslint-plugin-jsx-a11y</code> (recommended ruleset) added to <code>eslint.config.ts</code>; applied to <code>runtime/</code>, <code>apps/auth/</code>, <code>packages/ui/</code>, and <code>plugins/</code>; <code>pnpm lint</code> and the CI <code>lint</code> job pass with no suppressions</li><li><code>packages/ui</code>: four new semantic tokens (<code>--sv-color-error</code>, <code>--sv-color-error-text</code>, <code>--sv-color-success</code>, <code>--sv-color-success-text</code>) paired with icon/text convention; <code>prefers-reduced-motion</code> applied to animated components (Dialog, future Drawer/Toast); <code>:focus-visible</code> outline via <code>--sv-color-focus-ring</code> codified on all interactive components (<code>@sovereignfs/ui</code> <strong>minor</strong> bump)</li><li>Audit + fix: runtime shell chrome, <code>apps/auth</code> login/registration, Console, Launcher, and Account against WCAG 2.1 AA — roles, labels, keyboard interactions, focus order, color contrast</li><li><code>docs/design-system.md</code>: contrast commitment table (4.5:1 text, 3:1 UI components) for all semantic color pairs; focus-visible token guidance; per-component a11y spec (roles, keyboard table, ARIA attributes, focus order)</li><li><code>docs/plugin-development.md</code>: new &quot;Accessibility&quot; section (semantic HTML, form labels, icon <code>aria-hidden</code>/<code>aria-label</code> convention, color independence, keyboard operability, custom widget ARIA patterns, live regions, <code>prefers-reduced-motion</code>)</li><li><code>docs/sovereign-proposal-plan-srs.md</code>: NFR-11 — WCAG 2.1 AA for platform-owned UI</li></ul><p><strong>Dependencies:</strong> Task 0.5.17 (Icon a11y convention), Task 0.5.25 (touch targets)</p><p><strong>SRS reference:</strong> RFC 0025, NFR-11</p><p><strong>Review checklist:</strong></p><ul><li><code>pnpm lint</code> passes with <code>eslint-plugin-jsx-a11y</code> enabled; no inline suppressions</li><li>Keyboard-only navigation covers: log in, open and close an overlay plugin, navigate Console user list, change a setting in Account</li><li>Every semantic color pair documented in <code>docs/design-system.md</code> meets 4.5:1 text contrast and 3:1 UI-component contrast</li><li>Plugin dev guide &quot;Accessibility&quot; section covers all items from RFC 0025</li></ul><hr>',20)])])}const h=o(c,[["render",s]]);export{m as __pageData,h as default};
